// generateInstallCLISteps generates YAML steps to install or build the gh-aw CLI.
// In dev mode: builds from source using Setup Go + Build gh-aw (./gh-aw binary available)
// In release mode: installs the released CLI via the setup-cli action (gh aw available)
// In action mode: installs the released CLI via the gh-aw-actions/setup-cli action (gh aw available)
// When a resolver is provided and the mode is release or action, emits SHA-pinned references
// for supply-chain integrity. Falls back to tag-based references for backward compatibility.
func generateInstallCLISteps(actionMode ActionMode, version string, actionTag string, resolver ActionSHAResolver) string {
	if actionMode == ActionModeDev {
		return `      - name: Setup Go
        uses: ` + GetActionPin("actions/setup-go") + `
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

`
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}

	// Resolve the setup-cli action reference with SHA pinning if possible.
	// Pattern mirrors getActionRef() in copilot_setup.go and resolveSetupActionRef() in action_reference.go.
	actionRepo := "github/gh-aw/actions/setup-cli"
	if actionMode == ActionModeAction {
		actionRepo = "github/gh-aw-actions/setup-cli"
	}

	setupCLIRef := actionRepo + "@" + cliTag

	if resolver != nil {
		sha, err := resolver.ResolveSHA(actionRepo, cliTag)
		if err == nil && sha != "" {
			setupCLIRef = formatActionReference(actionRepo, sha, cliTag)
		}
	}

	return `      - name: Install gh-aw
        uses: ` + setupCLIRef + `
        with:
          version: ` + cliTag + `

`
}

