// resolveSetupCLISHA attempts to resolve the commit SHA for the setup-cli action.
// Mirrors the pattern in copilot_setup.go getActionRef().
// Returns the SHA on success, or empty string if resolution fails or no resolver is available.
func resolveSetupCLISHA(actionMode ActionMode, version string, actionTag string, resolver ActionSHAResolver) string {
	if resolver == nil {
		return ""
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}
	if cliTag == "" || cliTag == "dev" {
		return ""
	}

	actionRepo := "github/gh-aw/actions/setup-cli"
	if actionMode == ActionModeAction {
		actionRepo = "github/gh-aw-actions/setup-cli"
	}

	sha, err := resolver.ResolveSHA(actionRepo, cliTag)
	if err != nil || sha == "" {
		return ""
	}
	return sha
}

